import{_ as a,o as e,c as o,a4 as r}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"猫眼效应","description":"","frontmatter":{"title":"猫眼效应","phenomenon":"chatoyancy"},"headers":[],"relativePath":"zh/optical-phenomena/chatoyancy.md","filePath":"zh/optical-phenomena/chatoyancy.md","lastUpdated":1784176423000}'),d={name:"zh/optical-phenomena/chatoyancy.md"};function h(n,t,i,l,c,s){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="猫眼效应" tabindex="-1">猫眼效应 <a class="header-anchor" href="#猫眼效应" aria-label="Permalink to &quot;猫眼效应&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>猫眼效应是当宝石内含大量平行排列的纤维状包裹体、空洞或管状 结构时，弧面切割下垂直于包裹体走向的弧顶呈现一道明亮游动的 光带，类似猫的眼睛。最著名的&quot;金绿猫眼&quot;（cymophane）是该效应 的命名来源。其他如碧玺猫眼、磷灰石猫眼、月光石（虽为不同机 制但视觉相似）。</p><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>单向反射：所有包裹体沿同一方向延展（如金绿宝石中沿 c 轴的 空管）。从顶部观察，每根管子都把垂直方向的光反射到眼睛中。 整个包裹体群反射的光被几何约束成一道垂直于走向的窄光带。包 括包裹体越多、越细、越平行，效果越强。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>包裹体形态</th><th>宿主矿物</th></tr></thead><tbody><tr><td>Chrysoberyl Cat&#39;s-eye / 金绿猫眼</td><td>hollow tubes along c-axis</td><td>Chrysoberyl</td></tr><tr><td>Tourmaline Cat&#39;s-eye / 碧玺猫眼</td><td>parallel hollow channels</td><td>Elbaite</td></tr><tr><td>Apatite Cat&#39;s-eye / 磷灰石猫眼</td><td>fibrous inclusions</td><td>Apatite</td></tr><tr><td>Hawk&#39;s-eye / 鹰眼石</td><td>crocidolite fibers</td><td>Quartz (pseudomorph)</td></tr><tr><td>Tiger&#39;s-eye / 虎眼石</td><td>crocidolite fibers (oxidized)</td><td>Quartz (pseudomorph)</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',8)])])}const u=a(d,[["render",h]]);export{m as __pageData,u as default};
